function insertBST(root, val) {
  if(!root) return new TreeNode(val);
  if(val<root.val) root.left=insertBST(root.left,val);
  else root.right=insertBST(root.right,val);
  return root;
}

function levelOrder(root) {
  if(!root) return [];
  const res=[], q=[root];
  while(q.length){const lv=[], sz=q.length;
    for(let i=0;i<sz;i++){const n=q.shift();lv.push(n.val);if(n.left)q.push(n.left);if(n.right)q.push(n.right);}
    res.push(lv);
  } return res;
}

function climbStairs(n) {
  if(n<=2) return n;
  let a=1, b=2;
  for(let i=3;i<=n;i++){const c=a+b;a=b;b=c;}
  return b;
}

function movingAverage(samples, k) {
  const r=[]; let s=0;
  for(let i=0;i<k;i++) s+=samples[i];
  r.push(s/k);
  for(let i=k;i<samples.length;i++){s+=samples[i]-samples[i-k];r.push(s/k);}
  return r;
}

function zeroCrossingRate(samples) {
  let c=0;
  for(let i=1;i<samples.length;i++)
    if((samples[i]>=0&&samples[i-1]<0)||(samples[i]<0&&samples[i-1]>=0)) c++;
  return c/samples.length;
}

function frameEnergy(samples, frameSize) {
  const r=[];
  for(let i=0;i+frameSize<=samples.length;i+=frameSize){
    let e=0; for(let j=i;j<i+frameSize;j++) e+=samples[j]*samples[j];
    r.push(e);
  } return r;
}

function invertTree(root) {
  if(!root) return null;
  const t=root.left; root.left=root.right; root.right=t;
  invertTree(root.left); invertTree(root.right);
  return root;
}

function isValidBST(root) {
  function check(n,min,max){
    if(!n)return true;
    if(n.val<=min||n.val>=max)return false;
    return check(n.left,min,n.val)&&check(n.right,n.val,max);
  }
  return check(root,-Infinity,Infinity);
}

function coinChange(coins, amount) {
  const dp=new Array(amount+1).fill(Infinity); dp[0]=0;
  for(let i=1;i<=amount;i++)
    for(const c of coins) if(c<=i&&dp[i-c]+1<dp[i]) dp[i]=dp[i-c]+1;
  return dp[amount]===Infinity?-1:dp[amount];
}

function bfsDistance(graph, start) {
  const d={[start]:0}, q=[start];
  while(q.length){const n=q.shift();for(const nb of(graph[n]||[])){if(d[nb]===undefined){d[nb]=d[n]+1;q.push(nb);}}}
  return d;
}

class MinStack {
  constructor(){this.s=[];this.m=[];}
  push(v){this.s.push(v);if(!this.m.length||v<=this.m[this.m.length-1])this.m.push(v);}
  pop(){const v=this.s.pop();if(v===this.m[this.m.length-1])this.m.pop();}
  top(){return this.s[this.s.length-1];}
  getMin(){return this.m[this.m.length-1];}
}

class CircBuf {
  constructor(sz){this.b=new Array(sz).fill(0);this.sz=sz;this.w=0;this.r=0;this.c=0;}
  write(s){this.b[this.w]=s;this.w=(this.w+1)%this.sz;if(this.c<this.sz)this.c++;else this.r=(this.r+1)%this.sz;}
  read(){if(!this.c)return null;const v=this.b[this.r];this.r=(this.r+1)%this.sz;this.c--;return v;}
}

function detectPeaks(samples, threshold) {
  const p=[];
  for(let i=1;i<samples.length-1;i++)
    if(samples[i]>threshold&&samples[i]>samples[i-1]&&samples[i]>samples[i+1]) p.push(i);
  return p;
}

function convolve(signal, kernel) {
  const o=new Array(signal.length+kernel.length-1).fill(0);
  for(let i=0;i<signal.length;i++) for(let j=0;j<kernel.length;j++) o[i+j]+=signal[i]*kernel[j];
  return o;
}

function lcs(s1, s2) {
  const m=s1.length,n=s2.length;
  const dp=Array.from({length:m+1},()=>new Array(n+1).fill(0));
  for(let i=1;i<=m;i++) for(let j=1;j<=n;j++)
    dp[i][j]=s1[i-1]===s2[j-1]?dp[i-1][j-1]+1:Math.max(dp[i-1][j],dp[i][j-1]);
  return dp[m][n];
}

function numIslands(grid) {
  let c=0;
  function dfs(i,j){
    if(i<0||i>=grid.length||j<0||j>=grid[0].length||grid[i][j]==='0')return;
    grid[i][j]='0'; dfs(i+1,j);dfs(i-1,j);dfs(i,j+1);dfs(i,j-1);
  }
  for(let i=0;i<grid.length;i++) for(let j=0;j<grid[0].length;j++)
    if(grid[i][j]==='1'){c++;dfs(i,j);}
  return c;
}

function lca(root, p, q) {
  while(root){
    if(p<root.val&&q<root.val) root=root.left;
    else if(p>root.val&&q>root.val) root=root.right;
    else return root;
  }
}

function topoSort(n, edges) {
  const adj=Array.from({length:n},()=>[]),deg=new Array(n).fill(0);
  for(const[f,t]of edges){adj[f].push(t);deg[t]++;}
  const q=[]; for(let i=0;i<n;i++) if(!deg[i])q.push(i);
  const r=[]; while(q.length){const nd=q.shift();r.push(nd);for(const nb of adj[nd]){deg[nb]--;if(!deg[nb])q.push(nb);}}
  return r;
}

function rmsLevel(samples, frameSize) {
  const r=[];
  for(let i=0;i+frameSize<=samples.length;i+=frameSize){
    let s=0; for(let j=i;j<i+frameSize;j++) s+=samples[j]*samples[j];
    r.push(Math.sqrt(s/frameSize));
  } return r;
}

function noiseGate(samples, frameSize, threshold) {
  const o=[...samples];
  for(let i=0;i+frameSize<=o.length;i+=frameSize){
    let s=0; for(let j=i;j<i+frameSize;j++) s+=o[j]*o[j];
    if(Math.sqrt(s/frameSize)<threshold) for(let j=i;j<i+frameSize;j++) o[j]=0;
  } return o;
}

function ampToDb(amp) {
  if(amp===0) return -Infinity;
  return 20*Math.log10(Math.abs(amp));
}
function dbToAmp(db) {
  return Math.pow(10, db/20);
}

function downsample(samples, factor) {
  const r=[]; let s=0;
  for(let i=0;i<factor&&i<samples.length;i++) s+=samples[i];
  r.push(s/factor);
  for(let i=factor;i<samples.length;i++){s+=samples[i]-samples[i-factor];r.push(s/factor);}
  const d=[]; for(let i=0;i<r.length;i+=factor) d.push(r[i]);
  return d;
}
